#[unsafe(no_mangle)]
pub unsafe extern "C" fn go_program_list_len(ptr: *const c_void) -> usize {
    if ptr.is_null() {
        return 0;
    }
    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        let list = &*(ptr as *const Vec<chia_sdk_bindings::Program>);
        list.len()
    })).unwrap_or(0)
}

#[unsafe(no_mangle)]
pub unsafe extern "C" fn go_program_list_get(ptr: *const c_void, index: usize, out: *mut *mut c_void) -> i32 {
    catch(|| {
        if ptr.is_null() {
            return Err(bindy::Error::Custom("null pointer".to_string()));
        }
        let list = &*(ptr as *const Vec<chia_sdk_bindings::Program>);
        if index >= list.len() {
            return Err(bindy::Error::Custom("index out of bounds".to_string()));
        }
        *out = Box::into_raw(Box::new(list[index].clone())) as *mut c_void;
        Ok(())
    })
}

#[unsafe(no_mangle)]
pub unsafe extern "C" fn go_program_list_free(ptr: *mut c_void) {
    if !ptr.is_null() {
        let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            drop(Box::from_raw(ptr as *mut Vec<chia_sdk_bindings::Program>));
        }));
    }
}

