#[unsafe(no_mangle)]
pub unsafe extern "C" fn go_puzzle_new(
    puzzle_hash_ptr: *const u8, puzzle_hash_len: usize,
    program: *const std::ffi::c_void,
    mod_hash_ptr: *const u8, mod_hash_len: usize,
    args: *const std::ffi::c_void,
    out: *mut *mut c_void,
) -> i32 {
    catch(|| {
        let inner = chia_sdk_bindings::Puzzle {
            puzzle_hash: { if puzzle_hash_ptr.is_null() { return Err(bindy::Error::Custom(format!("puzzle_hash must not be null"))); } bindy::IntoRust::<_, _, bindy::Go>::into_rust(std::slice::from_raw_parts(puzzle_hash_ptr, puzzle_hash_len).to_vec(), &bindy::GoContext)? },
            program: { if (program).is_null() { return Err(bindy::Error::Custom(format!("program must not be null"))); } (*((program) as *const chia_sdk_bindings::Program)).clone() },
            mod_hash: { if mod_hash_ptr.is_null() { return Err(bindy::Error::Custom(format!("mod_hash must not be null"))); } bindy::IntoRust::<_, _, bindy::Go>::into_rust(std::slice::from_raw_parts(mod_hash_ptr, mod_hash_len).to_vec(), &bindy::GoContext)? },
            args: if args.is_null() { None } else { Some((*((args) as *const chia_sdk_bindings::Program)).clone()) }
        };
        *out = Box::into_raw(Box::new(inner)) as *mut c_void;
        Ok(())
    })
}

